<?php require_once __DIR__.'/../../middleware/bootstrap.php';$a=user();if(($a['role_id']??0)<2)out(['error'=>'Forbidden'],403);$d=input();$pdo=db();$pdo->beginTransaction();$st=$pdo->prepare('select * from wallet_requests where id=? and status="pending" for update');$st->execute([$d['id']]);$r=$st->fetch();if(!$r){$pdo->rollBack();out(['error'=>'Not found'],404);} $pdo->prepare('update wallet_requests set status="approved",reviewed_by=?,reviewed_at=now() where id=?')->execute([$a['id'],$r['id']]);$pdo->prepare('update wallets set balance=balance+? where user_id=?')->execute([$r['amount'],$r['user_id']]);$pdo->prepare('insert into transactions(user_id,type,amount,status,reference,created_at)values(?,"deposit",?,"completed",?,now())')->execute([$r['user_id'],$r['amount'],'wallet-request-'.$r['id']]);$pdo->commit();out(['ok'=>true]);
